CREATE TABLE IF NOT EXISTS `deliveryPoints` (
  `id` int AUTO_INCREMENT NOT NULL,
  `tenantId` int NOT NULL,
  `name` varchar(255) NOT NULL,
  `type` enum('DOCK','PHARMACY') NOT NULL,
  `externalCode` varchar(100) NOT NULL,
  `description` text,
  `floor` varchar(50),
  `isActive` boolean NOT NULL DEFAULT true,
  `createdAt` timestamp NOT NULL DEFAULT (now()),
  `updatedAt` timestamp NOT NULL DEFAULT (now()) ON UPDATE CURRENT_TIMESTAMP,
  CONSTRAINT `deliveryPoints_id` PRIMARY KEY(`id`)
);

CREATE TABLE IF NOT EXISTS `deliveryLogs` (
  `id` int AUTO_INCREMENT NOT NULL,
  `tenantId` int NOT NULL,
  `orderId` int NOT NULL,
  `deliveryPointId` int NOT NULL,
  `status` enum('ARRIVED_COMPLEX','DEPARTED_TO_UNIT','ARRIVED_UNIT','RECEIVING_STARTED','RECEIVE_COMPLETE') NOT NULL,
  `timestamp` timestamp NOT NULL DEFAULT (now()),
  `userId` int,
  `notes` text,
  `createdAt` timestamp NOT NULL DEFAULT (now()),
  CONSTRAINT `deliveryLogs_id` PRIMARY KEY(`id`)
);

CREATE INDEX IF NOT EXISTS `deliveryPoints_tenantId_idx` ON `deliveryPoints` (`tenantId`);
CREATE INDEX IF NOT EXISTS `deliveryPoints_tenantId_type_idx` ON `deliveryPoints` (`tenantId`,`type`);
CREATE INDEX IF NOT EXISTS `deliveryPoints_externalCode_idx` ON `deliveryPoints` (`tenantId`,`externalCode`);
CREATE INDEX IF NOT EXISTS `deliveryLogs_tenantId_idx` ON `deliveryLogs` (`tenantId`);
CREATE INDEX IF NOT EXISTS `deliveryLogs_orderId_idx` ON `deliveryLogs` (`orderId`);
CREATE INDEX IF NOT EXISTS `deliveryLogs_tenantId_orderId_idx` ON `deliveryLogs` (`tenantId`,`orderId`);
CREATE INDEX IF NOT EXISTS `deliveryLogs_deliveryPointId_idx` ON `deliveryLogs` (`deliveryPointId`);
CREATE INDEX IF NOT EXISTS `deliveryLogs_status_idx` ON `deliveryLogs` (`status`);
CREATE INDEX IF NOT EXISTS `deliveryLogs_timestamp_idx` ON `deliveryLogs` (`timestamp`);

